// Get webhook data directly from the Webhook node
const webhookData = $('Webhook').first().json.body;

// Get merged API data
const item = $input.first().json;

// Attack data from webhook
const failedAttempts = webhookData.failed_attempts;
const timespanSeconds = webhookData.timespan_seconds;
const targetUser = webhookData.target_user;
const targetServer = webhookData.target_server;
const protocol = webhookData.protocol;
const ip = webhookData.ip;

// AbuseIPDB data
const abuseScore = item.data.abuseConfidenceScore;
const isTor = item.data.isTor;
const totalReports = item.data.totalReports;
const country = item.data.countryCode;
const isp = item.data.isp;
const lastReported = item.data.lastReportedAt;

// VirusTotal data
const vtMalicious = item.data.attributes.last_analysis_stats.malicious;

// Attack velocity
const attemptsPerMinute = Math.round((failedAttempts / timespanSeconds) * 60);

// Is high value account targeted
const isAdminTarget = ['admin','root','administrator'].includes(
  targetUser.toLowerCase()
);

// Weighted brute force risk score
const riskScore = Math.min(100, Math.round(
  (abuseScore * 0.30) +
  (vtMalicious * 1.5) +
  (isTor ? 20 : 0) +
  (attemptsPerMinute > 60 ? 20 : attemptsPerMinute > 20 ? 10 : 5) +
  (isAdminTarget ? 15 : 0) +
  (totalReports > 50 ? 10 : 0)
));

// Severity label
let severity = "LOW";
if (riskScore >= 80) severity = "CRITICAL";
else if (riskScore >= 60) severity = "HIGH";
else if (riskScore >= 40) severity = "MEDIUM";

return [{
  json: {
    ip,
    riskScore,
    severity,
    failedAttempts,
    attemptsPerMinute,
    targetUser,
    targetServer,
    protocol,
    isAdminTarget,
    vtMalicious,
    abuseScore,
    isTor,
    totalReports,
    country,
    isp,
    lastReported
  }
}];

const ip = $input.first().json.body.ip;

// Check IP was provided
if (!ip) {
  throw new Error('No IP address provided in request body');
}

// Check valid IP format
const ipRegex = /^(\d{1,3}\.){3}\d{1,3}$/;
if (!ipRegex.test(ip)) {
  throw new Error(`Invalid IP format: ${ip}`);
}

// Check each octet is 0-255
const parts = ip.split('.').map(Number);
if (parts.some(p => p < 0 || p > 255)) {
  throw new Error(`Invalid IP range: ${ip}`);
}

// Block private/internal IPs 
if (
  parts[0] === 10 ||
  parts[0] === 127 ||
  parts[0] === 0 ||
  (parts[0] === 192 && parts[1] === 168) ||
  (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31)
) {
  throw new Error(`Private IP skipped: ${ip}`);
}

// Valid public IP 
return $input.all();
